INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00334', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察受理報案初抵現場人員應實施犯罪調查，於必要時得封鎖犯罪現場並為即時之勘察。就本項 警察人員進行初步查訪、調查及勘察採證，以下敘述何者正確？', '["於刑案現場發現犯罪嫌疑人時，應留在原地即刻對其採取指紋、掌紋或腳印", "於刑案現場以外處所發現犯罪嫌疑人時，應將其帶回現場進行犯罪模擬釐清案情", "刑案現場之處所為住宅、車輛時，就其內之物品實施採證可不經權利人之同意", "現場非病死案件檢察官認顯無犯罪嫌疑時，可交由司法警察官會同法醫師進行相驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00335', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察應以專業、效率之精神處理現場及偵查案件，並秉持同理心及尊重態度，關懷協助被害 人及家屬，適時提供相關資訊及服務。試問有關警察維護被害人權益之條文規範，以下敘述何者 錯誤？', '["被害人接受偵訊時陪同在場之人得陳述意見", "被害人無偵查不公開之義務可協助其媒體採訪", "被害人接受偵訊時得聲請遮蔽或適當隔離被告", "被害人於證據有遭偽變造之虞時得聲請證據保全"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00336', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '為保護學生安全，警察於治安顧慮場域擴大臨檢，發現通緝人犯甲旋即予以逮捕，但因未隨身攜 帶通緝書未能即時提示，稍後即將甲解送地檢署。惟過程中甲提出提審聲請，經法院核發提審票 。試問，就本項逮捕之提審規定，以下敘述何者正確？', '["有關聲請提審意旨，警察應以口頭告知為原則", "有關聲請提審意旨，應告知甲本人及其指定之親友", "警察若已釋放人犯，於收受提審票時仍應將人犯逮捕解交法院", "人犯已解送地檢署聲請羈押，警察於收受提審票時仍應將其解交法院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00337', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '派出所員警夜間巡邏過程，發現甲騎乘機車形跡可疑而將其攔停，見其眼神閃避、態度詭異而要 其接受詢問調查。稍後，並從其機車坐墊下搜出多瓶酒類，員警乃將甲帶回進一步偵訊製作筆錄。 試問，就本項攔停、酒測、搜扣及筆錄製作，以下敘述何者正確？', '["員警對甲實施臨檢攔停時，應對其行權利告知", "員警對甲實施呼氣酒測時，其應可委任辯護人", "員警對甲搜扣相關酒瓶時，應待其委任辯護人到場", "員警將甲帶回製作筆錄時，其委任辯護人應可接見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00338', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察官或司法警察因調查犯罪嫌疑人犯罪情形及蒐集證據之必要，依法得以使用通知書通知 犯罪嫌疑人、證人到場接受詢問。有關警察實施本項詢問程序過程，下列敘述何者最為正確？', '["對於兩者實施詢問，皆有辯護人陪同權利", "對於兩者實施詢問，皆有拒絕到場陳述權利", "對於兩者實施詢問，皆有誠實供述義務", "對於兩者實施詢問，皆有簽名具結義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00339', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察實施犯罪偵查執行通訊監察，應本諸公平、公正原則並嚴守業務機密，不得違法監察或洩漏 提供使用監察所得之資料。下列有關法官核發通訊監察書後之執行程序之敘述，何者正確？', '["實施通訊監察執行期間，應於每週派員取回案件監錄內容", "實施通訊監察執行期間，應於每月作成案件監錄報告書陳報法院", "實施通訊監察執行結束，原則上應於一個月內通知受監察人", "實施通訊監察執行結束，原則上應於每季銷燬案件監錄資料"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00340', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察執行路檢，發現 A 駕駛車輛於前方路口刻意繞道頗為可疑，故以無線電通知線上巡邏警網 攔停其車。稍後，甲警於詢問A為何繞道的緣由過程，發覺車內有淡淡塑膠焦味，且有數包白色 粉末散落，此時乙警懷疑A使用「愷他命」乃詢問有關白色粉末由來等情。試問為確保A供述 作為犯罪證據，以下敘述何者錯誤？', '["甲警詢問A時可查驗身分", "甲警詢問A時其可主張緘默權", "乙警詢問A時其可選任辯護人", "乙警詢問A時應該全程連續錄音"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00341', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察實施犯罪調查，必要時得封鎖犯罪現場並為即時之勘察，並且實施相關封鎖時應派員於封鎖 線外警戒，非經現場指揮官同意任何人不得進入。試問有關本項勘察勤務，以下敘述何者錯誤？', '["本項現場勘察屬於任意偵查處分", "重大刑案應由管轄警察分局長擔任現場指揮官", "特殊案件可由分局偵查隊負責現場勘察採證", "現場依任務需要，將現有人員區分為調查組及勘察組，原則上調查組負責搜尋附近監視影像"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00342', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依據警察偵查犯罪相關法令規定，對幫派涉組織犯罪案件之證人或與其有密切利害關係之人、檢 舉人及被害人，應依證人保護法及組織犯罪防制條例規定。試問，有關警察偵辦組織犯罪保護證 人之程序，以下敘述何者錯誤？', '["有保護身分必要證人之保護書不可提供辯護人閱卷", "有保護身分必要證人之筆錄文書不可提供辯護人閱卷", "有保護身分必要證人之供述可不接受對質或詰問", "有保護身分必要證人之審理可採行不公開之方式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00343', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '為保護個人免於受到跟蹤騷擾行為侵擾，維護個人人格尊嚴，依法警察機關受理跟蹤騷擾行為案 件，應即開始調查、製作書面紀錄，並告知被害人得行使之權利及服務措施。試問，警察受理配 偶或家庭成員有關跟蹤騷擾行為之報案，以下敘述何者正確？', '["相關跟蹤騷擾行為應出於性或性別有關之主觀意識", "相關跟蹤騷擾行為該當刑法非告訴乃論之犯罪類型", "相關跟蹤騷擾行為該當犯嫌重大可聲請預防性羈押", "相關跟蹤騷擾行為於調查蒐證必要時可聲請調取票"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
